// src/routes/productSearch.ts
import { Router, Request, Response } from 'express';
import { getRepository } from 'typeorm';
import { Product } from '../entity/Product';

const router = Router();

router.get('/products/search', async (req: Request, res: Response) => {
  try {
    const {
      q,
      category,
      brand,
      minPrice,
      maxPrice,
      inStock,
      minRating,
      sortBy,
      sortDir,
      limit,
      offset,
    } = req.query as Record<string, string | undefined>;

    const conditions: string[] = [];

    if (q) conditions.push(`p.name ILIKE '%${q.replace(/'/g, "''")}%'`);
    if (category) conditions.push(`p.category = '${category.replace(/'/g, "''")}'`);
    if (brand) conditions.push(`p.brand = '${brand.replace(/'/g, "''")}'`);
    if (minPrice) conditions.push(`p.price >= ${Number(minPrice)}`);
    if (maxPrice) conditions.push(`p.price <= ${Number(maxPrice)}`);
    if (inStock !== undefined) conditions.push(`p.in_stock = ${inStock === 'true' ? 'TRUE' : 'FALSE'}`);
    if (minRating) conditions.push(`p.rating >= ${Number(minRating)}`);

    const sortable = ['name', 'price', 'rating', 'created_at'];
    let orderClause = 'ORDER BY p.created_at DESC';
    if (sortBy && sortable.includes(sortBy)) {
      orderClause = `ORDER BY p.${sortBy} ${sortDir?.toUpperCase() === 'DESC' ? 'DESC' : 'ASC'}`;
    }

    const limitNum = Math.min(Number(limit) || 20, 100);
    const offsetNum = Number(offset) || 0;

    const whereClause = conditions.length ? `WHERE ${conditions.join(' AND ')}` : '';

    const sql = `
      SELECT
        p.id,
        p.name,
        p.category,
        p.brand,
        p.price,
        p.in_stock,
        p.rating,
        p.created_at
      FROM products p
      ${whereClause}
      ${orderClause}
      LIMIT ${limitNum}
      OFFSET ${offsetNum};
    `;

    const products = await getRepository(Product).query(sql);
    res.json(products);
  } catch (error) {
    console.error('Product search error:', error);
    res.status(500).json({ message: 'Internal server error' });
  }
});

export default router;

